export const carMakes = Object.keys(carDatabase).sort();

export function getModelsForMake(make: string): CarModel[] {
  return carDatabase[make] || [];
}

export function getDefaultSpecs(make: string, model: string): CarModel | null {
  const models = carDatabase[make] || [];
  return models.find(m => m.model.toLowerCase() === model.toLowerCase()) || null;
}